    def dfs(x, y, path):
        if len(path) == k:
            return path
        if x < 0 or x >= len(grid) or y < 0 or y >= len(grid[0]):
            return None
        path.append(grid[x][y])
        result = None
        for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            result = min(result, dfs(x + dx, y + dy, path[:]), key=len)
        return result

    result = None
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            result = min(result, dfs(i, j, []), key=len)
    return result

